# install_python311.ps1# Installs Python 3.11 via winget if available, creates a venv using that interpreter,# upgrades pip/setuptools/wheel and installs requirements.txt.# Run from project backend folder: .\install_python311.ps1param(    [switch]$SkipDeps  # pass -SkipDeps to stop after creating venv)function Write-ErrorAndExit($msg){    Write-Host "ERROR: $msg" -ForegroundColor Red    exit 1}# Try winget install firstif (Get-Command winget -ErrorAction SilentlyContinue) {    Write-Host "winget found Gă÷ attempting to install Python 3.11..."    try {        winget install --id Python.Python.3.11 -e --silent --accept-package-agreements --accept-source-agreements    } catch {        Write-Host "winget installation failed or Python 3.11 package not found. Opening Python downloads page instead..."        Start-Process "https://www.python.org/downloads/release/python-311/"        Write-Host "Please install Python 3.11 manually and re-run this script. Exiting."        exit 1    }} else {    Write-Host "winget not found. Opening Python 3.11 download page in the browser..."    Start-Process "https://www.python.org/downloads/release/python-311/"    Write-Host "Please download & install Python 3.11, then re-run this script. Exiting."    exit 1}# Wait a bit to allow installer to finishStart-Sleep -Seconds 5# Verify py launcher can find 3.11$py311 = & py -3.11 --version 2>&1if ($LASTEXITCODE -ne 0) {    Write-Host "py launcher cannot find Python 3.11 yet. Trying to discover python.exe in common locations..."    $possible = @(        "$env:LOCALAPPDATA\Programs\Python\Python311\python.exe",        "C:\\Program Files\\Python311\\python.exe",        "C:\\Program Files\\Python311-32\\python.exe"    )    $pythonExe = $null    foreach ($p in $possible) {        if (Test-Path $p) { $pythonExe = $p; break }    }    if (-not $pythonExe) {        Write-ErrorAndExit "Python 3.11 installation not detected. Please restart your shell or provide the path to python.exe and re-run the script."    }} else {    # get full path via py    $pythonExe = & py -3.11 -c "import sys, json; print(sys.executable)" 2>$null}$pythonExe = $pythonExe -replace "\r|\n",""Write-Host "Using Python at: $pythonExe"# Create venvWrite-Host "Creating venv in .\venv using Python 3.11..."& "$pythonExe" -m venv venvif ($LASTEXITCODE -ne 0) { Write-ErrorAndExit "Failed to create venv" }# Upgrade pip/setuptools/wheel and install requirements (using the venv python so we don't need Activate)if (-not $SkipDeps) {    $venvPython = Join-Path -Path (Get-Location) -ChildPath "venv\Scripts\python.exe"    if (-not (Test-Path $venvPython)) { Write-ErrorAndExit "Cannot find venv python at $venvPython" }    Write-Host "Upgrading pip, setuptools, wheel..."    & $venvPython -m pip install --upgrade pip setuptools wheel    if ($LASTEXITCODE -ne 0) { Write-ErrorAndExit "Failed to upgrade pip/setuptools/wheel" }    Write-Host "Installing project dependencies from requirements.txt..."    & $venvPython -m pip install -r requirements.txt    if ($LASTEXITCODE -ne 0) { Write-ErrorAndExit "Failed to install dependencies. Check the output above." }}Write-Host "Done. To activate the venv and run the server:"Write-Host "  PowerShell: .\\venv\\Scripts\\Activate.ps1" -ForegroundColor GreenWrite-Host "  Then: python run.py" -ForegroundColor Greenexit 0